#!/usr/bin/env python3
"""Validate D99 recurrent routing microcircuit prototype artifacts."""
from __future__ import annotations
import argparse, json, sys
from pathlib import Path
REPORTS=["d98_upstream_manifest.json","d99_scale_report.json","d99_recurrent_training_report.json","d99_recurrent_loop_instrumentation_report.json","d99_recurrent_convergence_report.json","d99_recurrent_halting_report.json","d99_recurrent_oscillation_report.json","d99_recurrent_state_stability_report.json","d99_recurrent_state_noise_report.json","d99_recurrent_state_reset_report.json","d99_recurrent_usefulness_report.json","d99_one_step_ablation_report.json","d99_no_state_control_report.json","d99_shuffled_state_control_report.json","d99_low_cost_ood_top1_ambiguity_tail_report.json","d99_combined_ood_joint_boundary_carryover_report.json","d99_ood_scale_carryover_report.json","d99_stress_tail_carryover_report.json","d99_min_seed_worst_seed_report.json","d99_feature_noise_carryover_report.json","d99_feature_dropout_carryover_report.json","d99_calibration_pressure_carryover_report.json","d99_confidence_false_positive_report.json","d99_top1_guard_preservation_report.json","d99_top1_guard_ablation_control_report.json","d99_top1_guard_partial_corruption_control_report.json","d99_D68_preservation_report.json","d99_safety_margin_report.json","d99_oracle_distance_frontier_report.json","d99_support_cost_frontier_report.json","d99_label_shuffle_sentinel_report.json","d99_regime_label_leak_sentinel_report.json","d99_row_id_lookup_sentinel_report.json","d99_python_hash_lookup_sentinel_report.json","d99_file_order_artifact_sentinel_report.json","d99_seed_id_shortcut_sentinel_report.json","d99_hidden_state_label_leak_sentinel_report.json","d99_halt_step_shortcut_sentinel_report.json","d99_split_integrity_report.json","d99_overfit_memorization_report.json","d99_feature_importance_stability_report.json","d99_negative_controls_report.json","d99_truth_leak_oracle_isolation_report.json","d99_rust_invocation_report.json","d99_report_schema_metric_crosscheck_report.json","d99_deterministic_replay_report.json","aggregate_metrics.json","decision.json","summary.json","report.md"]
ALLOWED={"d99_recurrent_routing_microcircuit_prototype_confirmed","d99_recurrent_loop_utility_not_confirmed","d99_recurrent_tail_risk_detected","d99_recurrent_state_robustness_failure","d99_recurrent_calibration_failure","top1_guard_invariant_violation","d68_regression_detected","d99_truth_leak_or_oracle_contamination_detected","d99_shortcut_memorization_detected","d99_split_contamination_detected","d99_rust_fallback_detected","d99_invalid_metric_or_report_inconsistency","d99_invalid_or_incomplete_run"}
def load(p:Path): return json.loads(p.read_text(encoding="utf-8"))
def fail(m): print(f"D99 check failed: {m}",file=sys.stderr); sys.exit(1)
def main():
    p=argparse.ArgumentParser(); p.add_argument("--out",default="target/pilot_wave/d99_recurrent_routing_microcircuit_prototype"); args=p.parse_args(); out=Path(args.out)
    missing=[r for r in REPORTS if not (out/r).exists()]
    if missing: fail(f"missing reports {missing}")
    man=load(out/"d98_upstream_manifest.json"); agg=load(out/"aggregate_metrics.json"); dec=load(out/"decision.json"); summ=load(out/"summary.json"); m=agg.get("metrics",{})
    if dec.get("decision") not in ALLOWED: fail(f"bad decision {dec.get('decision')}")
    if dec.get("decision")!="d99_recurrent_routing_microcircuit_prototype_confirmed": fail(f"unexpected decision {dec.get('decision')}")
    if dec.get("next")!="D100_RECURRENT_ROUTING_MICROCIRCUIT_SCALE_CONFIRM": fail(f"unexpected next {dec.get('next')}")
    if dec.get("failed_jobs") or agg.get("failed_jobs") or m.get("failed_jobs"): fail("failed_jobs present")
    if dec.get("fallback_rows")!=0 or agg.get("fallback_rows")!=0 or m.get("fallback_rows")!=0: fail("fallback rows nonzero")
    d98=man.get("d98_artifacts",{})
    if man.get("requested_d98_commit")!="565986b2cdee64251d45e0048fe96f76a59b712b": fail("requested D98 commit mismatch")
    if not man.get("commit_present") and not (man.get("restore_or_rerun_attempted") and man.get("restore_or_rerun_succeeded")): fail("D98 commit missing without successful restore/rerun")
    if not man.get("artifact_present") or man.get("validation_status")!="passed": fail("D98 artifact/validation failed")
    if d98.get("decision")!="d98_surrogate_adversarial_scale_confirmed" or d98.get("next")!="D99_RECURRENT_ROUTING_MICROCIRCUIT_PROTOTYPE": fail("D98 handoff mismatch")
    if d98.get("best_fair_surrogate_arm")!="SURROGATE_SMALL_MLP_FAIR": fail("D98 best fair surrogate mismatch")
    gates=agg.get("positive_gates",{}); failed=[k for k,v in gates.items() if not v]
    if failed: fail(f"positive gates failed {failed}")
    for r in REPORTS:
        if r.endswith(".json") and r not in {"aggregate_metrics.json","decision.json","summary.json","d98_upstream_manifest.json"} and not load(out/r).get("passed",True): fail(f"{r} did not pass")
    checks={"best_arm":m.get("best_fair_recurrent_arm")=="D99_RECURRENT_HALTING_CONFIDENCE_FAIR","test":m.get("recurrent_test_accuracy",0)>=0.994,"ood":m.get("recurrent_ood_accuracy",0)>=0.9915,"stress":m.get("recurrent_stress_accuracy",0)>=0.991,"min_seed":m.get("recurrent_min_seed_accuracy",0)>=0.9905,"worst_seed":m.get("recurrent_worst_seed_accuracy",0)>=0.9895,"overfit":m.get("recurrent_overfit_gap",1)<=0.015,"false_conf":m.get("recurrent_false_confidence_rate",1)<=0.0046,"routing":m.get("recurrent_routing_failure_rows")==0,"D68":m.get("recurrent_D68_preservation_rate")==1.0,"top1":m.get("recurrent_top1_guard_preserved") is True and m.get("recurrent_top1_guard_weakened") is False,"truth":m.get("recurrent_truth_leak_audit_passed") is True,"oracle":m.get("recurrent_oracle_isolation_passed") is True,"teacher_distance":m.get("recurrent_distance_to_symbolic_teacher",1)<=0.025,"d98_distance":m.get("recurrent_distance_to_d98_surrogate",1)<=0.025,"oracle_distance":m.get("recurrent_distance_to_concrete_oracle_support",1)<=0.385,"support":m.get("recurrent_average_support_used",99)<=6.75,"avg_steps":m.get("recurrent_average_steps_used",99)<=5.0,"max_steps":m.get("recurrent_max_steps_used",99)<=8,"converge":m.get("recurrent_convergence_rate",0)>=0.998,"nonconv":m.get("recurrent_non_convergence_rate",1)<=0.001,"osc":m.get("recurrent_oscillation_rate",1)<=0.001,"halt_fp":m.get("recurrent_halting_false_positive_rate",1)<=0.0046,"stability":m.get("recurrent_state_stability_score",0)>=0.80,"decay":m.get("recurrent_state_delta_decay_rate",0)>0,"state_ablation":m.get("recurrent_state_ablation_delta",0)>=0.003,"shuffled":m.get("recurrent_shuffled_state_delta",0)>=0.003,"one_step":m.get("recurrent_one_step_ablation_delta",0)>=0.002,"no_state":m.get("recurrent_no_state_control_delta",0)>=0.002,"utility":m.get("recurrent_loop_usefulness_score",0)>=0.70,"tail_utility":m.get("recurrent_loop_usefulness_on_tail_score",0)>=0.70,"tail":m.get("recurrent_low_cost_ood_top1_tail_score",0)>=0.745,"min_tail":m.get("recurrent_min_seed_low_cost_ood_top1_tail_score",0)>=0.741,"combined":m.get("recurrent_combined_ood_joint_boundary_breakpoint",0)>=0.755,"min_combined":m.get("recurrent_min_seed_combined_ood_joint_boundary_breakpoint",0)>=0.752,"external":m.get("recurrent_external_required_accuracy",0)>=0.995,"joint":m.get("recurrent_joint_required_accuracy",0)>=0.994,"abstain":m.get("recurrent_indistinguishable_abstain_rate",0)>=0.9948,"wrong":m.get("recurrent_wrong_concrete_counter_rate",1)<=0.0007,"weak":m.get("recurrent_weak_top1_top2_path_failure_rate",1)<=0.0006,"false_joint":m.get("recurrent_top1_top2_sufficient_false_joint_rate",1)<=0.0015,"worst_tail":m.get("worst_tail_failure_rate",1)<=0.003,"mixed":m.get("mixed_tail_compound_failure_rate",1)<=0.004,"fp_tail":m.get("false_positive_confidence_tail_rate",1)<=0.0048,"noise1":m.get("recurrent_state_noise_1pct_accuracy",0)>=0.991,"noise3":m.get("recurrent_state_noise_3pct_accuracy",0)>=0.988,"noise5":m.get("recurrent_state_noise_5pct_accuracy",0)>=0.985,"reset":m.get("recurrent_state_reset_recovery_accuracy",0)>=0.985,"sentinel":m.get("sentinel_collapse_passed") is True,"memorization":m.get("memorization_risk_score",1)<=0.10,"rust":m.get("rust_path_invoked") is True,"fallback":m.get("fallback_rows")==0,"failed_jobs":m.get("failed_jobs")==[]}
    bad=[k for k,v in checks.items() if not v]
    if bad: fail(f"metric gates failed {bad}")
    if m.get("forbidden_feature_detected") or m.get("forbidden_feature_names") or m.get("route_distillation_label_leak_risk") or not m.get("split_integrity_passed") or m.get("train_test_ood_contamination_detected"): fail("feature/distillation/split audit failed")
    sentinel_limits={"label_shuffle_sentinel_accuracy":0.55,"regime_label_leak_sentinel_accuracy":0.56,"row_id_lookup_sentinel_accuracy":0.55,"python_hash_lookup_sentinel_accuracy":0.55,"file_order_artifact_sentinel_accuracy":0.55,"seed_id_shortcut_sentinel_accuracy":0.55,"hidden_state_label_leak_sentinel_accuracy":0.55,"halt_step_shortcut_sentinel_accuracy":0.55}
    if [k for k,v in sentinel_limits.items() if m.get(k,1)>v]: fail("sentinel shortcut failed")
    if summ.get("decision")!=dec.get("decision") or summ.get("next")!=dec.get("next") or summ.get("best_fair_recurrent_arm")!=m.get("best_fair_recurrent_arm"): fail("summary mismatch")
    print(json.dumps({"check":"passed","out":str(out),"decision":dec,"best_fair_recurrent_arm":m.get("best_fair_recurrent_arm"),"recurrent_test_accuracy":m.get("recurrent_test_accuracy"),"failed_jobs":m.get("failed_jobs")},indent=2))
if __name__=="__main__": main()
